const body = $json.body ?? $json;
const required = ['job_name', 'build_number', 'status'];
const missing = required.filter((key) => body[key] === undefined || body[key] === null || body[key] === '');
if (missing.length > 0) {
  throw new Error(`Missing required fields: ${missing.join(', ')}`);
}
return [{ json: body }];

